import subprocess
import re
import os
import tempfile
from google.cloud import storage


# Allowlist of permitted file extensions
ALLOWED_INPUT_EXTENSIONS = {'.jpg', '.jpeg', '.png', '.gif', '.bmp', '.tiff', '.tif', '.webp'}
ALLOWED_OUTPUT_EXTENSIONS = {'.jpg', '.jpeg', '.png', '.gif', '.bmp', '.tiff', '.tif', '.webp', '.pdf'}

# Allowlist of permitted ImageMagick convert options
ALLOWED_OPTIONS = {
    '-resize', '-quality', '-rotate', '-flip', '-flop', '-strip',
    '-auto-orient', '-thumbnail', '-gravity', '-extent', '-crop',
    '-colorspace', '-depth', '-density', '-compress'
}

# Allowlist for option value patterns
OPTION_VALUE_PATTERNS = {
    '-resize': re.compile(r'^\d{1,5}x\d{1,5}[!><%^]?$'),
    '-quality': re.compile(r'^\d{1,3}$'),
    '-rotate': re.compile(r'^-?\d{1,3}(\.\d{1,2})?$'),
    '-thumbnail': re.compile(r'^\d{1,5}x\d{1,5}[!><%^]?$'),
    '-gravity': re.compile(r'^(NorthWest|North|NorthEast|West|Center|East|SouthWest|South|SouthEast)$'),
    '-extent': re.compile(r'^\d{1,5}x\d{1,5}$'),
    '-crop': re.compile(r'^\d{1,5}x\d{1,5}\+\d{1,5}\+\d{1,5}$'),
    '-colorspace': re.compile(r'^(sRGB|RGB|CMYK|Gray)$'),
    '-depth': re.compile(r'^(8|16|32)$'),
    '-density': re.compile(r'^\d{1,4}$'),
    '-compress': re.compile(r'^(None|LZW|Zip|JPEG|RLE)$'),
}

# Flags that take no value
NO_VALUE_OPTIONS = {'-flip', '-flop', '-strip', '-auto-orient'}

# Maximum file size: 50MB
MAX_FILE_SIZE = 50 * 1024 * 1024

OUTPUT_BUCKET = os.environ.get('OUTPUT_BUCKET', '')


def validate_filename(filename):
    """Validate and sanitize filename to prevent path traversal and injection."""
    if not filename or not isinstance(filename, str):
        raise ValueError("Invalid filename: must be a non-empty string")

    # Prevent path traversal
    basename = os.path.basename(filename)
    if basename != filename.replace('/', '_'):
        # Allow subdirectories but normalize
        normalized = os.path.normpath(filename)
        if normalized.startswith('..') or normalized.startswith('/'):
            raise ValueError(f"Invalid filename: path traversal detected in '{filename}'")
        basename = os.path.basename(normalized)

    # Check for null bytes
    if '\x00' in filename:
        raise ValueError("Invalid filename: null bytes detected")

    # Validate characters - only allow alphanumeric, hyphens, underscores, dots, and forward slashes
    if not re.match(r'^[a-zA-Z0-9_\-./]+$', filename):
        raise ValueError(f"Invalid filename: contains disallowed characters in '{filename}'")

    return filename


def validate_extension(filename, allowed_extensions):
    """Validate file extension against allowlist."""
    _, ext = os.path.splitext(filename)
    ext = ext.lower()
    if ext not in allowed_extensions:
        raise ValueError(
            f"Invalid file extension '{ext}'. Allowed: {', '.join(sorted(allowed_extensions))}"
        )
    return ext


def validate_convert_options(options_str):
    """Parse and validate ImageMagick convert options against allowlist."""
    if not options_str:
        return []

    if not isinstance(options_str, str):
        raise ValueError("Options must be a string")

    # Limit total options string length
    if len(options_str) > 500:
        raise ValueError("Options string too long")

    tokens = options_str.split()
    validated_args = []
    i = 0

    while i < len(tokens):
        token = tokens[i]

        if token not in ALLOWED_OPTIONS:
            raise ValueError(f"Disallowed option: '{token}'. Allowed: {', '.join(sorted(ALLOWED_OPTIONS))}")

        validated_args.append(token)

        if token in NO_VALUE_OPTIONS:
            i += 1
            continue

        # This option requires a value
        if i + 1 >= len(tokens):
            raise ValueError(f"Option '{token}' requires a value")

        value = tokens[i + 1]

        # Validate value doesn't look like a flag/option (unless it's a negative number for rotate)
        if value.startswith('-') and token != '-rotate':
            raise ValueError(f"Invalid value for '{token}': '{value}'")

        # Validate value against pattern if we have one
        if token in OPTION_VALUE_PATTERNS:
            pattern = OPTION_VALUE_PATTERNS[token]
            if not pattern.match(value):
                raise ValueError(
                    f"Invalid value for '{token}': '{value}' does not match expected pattern"
                )

        validated_args.append(value)
        i += 2

    return validated_args


def convert_image(event, context):
    """Cloud Function triggered by Cloud Storage to convert images using ImageMagick.

    Args:
        event (dict): Event payload containing Cloud Storage object metadata.
        context (google.cloud.functions.Context): Event context.
    """
    try:
        # Extract and validate event data
        bucket_name = event.get('bucket')
        file_name = event.get('name')
        file_size = int(event.get('size', 0))
        metadata = event.get('metadata', {}) or {}

        if not bucket_name or not file_name:
            print("Error: Missing bucket or filename in event")
            return

        # Validate bucket name
        if not re.match(r'^[a-z0-9][a-z0-9._-]{1,220}[a-z0-9]$', bucket_name):
            print("Error: Invalid bucket name")
            return

        # Validate input filename
        try:
            file_name = validate_filename(file_name)
            validate_extension(file_name, ALLOWED_INPUT_EXTENSIONS)
        except ValueError as e:
            print(f"Error: Input file validation failed: {e}")
            return

        # Check file size
        if file_size > MAX_FILE_SIZE:
            print(f"Error: File too large ({file_size} bytes). Maximum: {MAX_FILE_SIZE} bytes")
            return

        # Extract and validate output format from metadata
        output_format = metadata.get('output_format', '.png')
        if not output_format.startswith('.'):
            output_format = '.' + output_format
        output_format = output_format.lower()

        try:
            validate_extension('output' + output_format, ALLOWED_OUTPUT_EXTENSIONS)
        except ValueError as e:
            print(f"Error: Output format validation failed: {e}")
            return

        # Extract and validate conversion options from metadata
        options_str = metadata.get('convert_options', '')
        try:
            convert_args = validate_convert_options(options_str)
        except ValueError as e:
            print(f"Error: Options validation failed: {e}")
            return

        # Determine output bucket
        output_bucket_name = OUTPUT_BUCKET if OUTPUT_BUCKET else bucket_name
        if not re.match(r'^[a-z0-9][a-z0-9._-]{1,220}[a-z0-9]$', output_bucket_name):
            print("Error: Invalid output bucket name")
            return

        # Prevent infinite loops if output goes to same bucket
        base_name, _ = os.path.splitext(os.path.basename(file_name))
        output_file_name = f"converted/{base_name}{output_format}"

        if output_bucket_name == bucket_name and output_file_name == file_name:
            print("Skipping: output would overwrite input, potential infinite loop")
            return

        # Skip if this is already a converted file (prevent re-triggering)
        if file_name.startswith('converted/'):
            print("Skipping: file is already in converted/ directory")
            return

        # Download the file to a secure temp directory
        storage_client = storage.Client()
        source_bucket = storage_client.bucket(bucket_name)
        source_blob = source_bucket.blob(file_name)

        if not source_blob.exists():
            print(f"Error: Source file does not exist: gs://{bucket_name}/{file_name}")
            return

        with tempfile.TemporaryDirectory() as tmp_dir:
            # Use sanitized basename for local files
            safe_input_name = re.sub(r'[^a-zA-Z0-9._-]', '_', os.path.basename(file_name))
            safe_output_name = re.sub(r'[^a-zA-Z0-9._-]', '_', os.path.basename(output_file_name))

            input_path = os.path.join(tmp_dir, safe_input_name)
            output_path = os.path.join(tmp_dir, safe_output_name)

            # Verify paths are within temp directory (defense in depth)
            if not os.path.realpath(input_path).startswith(os.path.realpath(tmp_dir)):
                print("Error: Input path escapes temp directory")
                return
            if not os.path.realpath(output_path).startswith(os.path.realpath(tmp_dir)):
                print("Error: Output path escapes temp directory")
                return

            # Download source file
            source_blob.download_to_filename(input_path)
            print(f"Downloaded gs://{bucket_name}/{file_name} to {input_path}")

            # Verify the downloaded file is actually an image using ImageMagick identify
            identify_cmd = ['/usr/bin/identify', '-ping', input_path]
            identify_result = subprocess.call(
                identify_cmd,
                timeout=30,
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL
            )
            if identify_result != 0:
                print(f"Error: File is not a valid image: {file_name}")
                return

            # Build the convert command with validated arguments
            # Use absolute path to ImageMagick convert binary
            cmd = ['/usr/bin/convert', input_path] + convert_args + [output_path]

            # Log the command (without full paths for security)
            sanitized_log = ['convert', safe_input_name] + convert_args + [safe_output_name]
            print(f"Executing: {' '.join(sanitized_log)}")

            # Execute the conversion with resource limits
            result = subprocess.call(
                cmd,
                timeout=120,
                stdout=subprocess.DEVNULL,
                stderr=subprocess.PIPE,
                env={
                    'PATH': '/usr/bin',
                    'MAGICK_MEMORY_LIMIT': '256MiB',
                    'MAGICK_MAP_LIMIT': '512MiB',
                    'MAGICK_DISK_LIMIT': '1GiB',
                    'MAGICK_TIME_LIMIT': '60',
                    'MAGICK_THREAD_LIMIT': '2',
                }
            )

            if result != 0:
                print(f"Error: ImageMagick convert failed with exit code {result}")
                return

            # Verify output file exists and is valid
            if not os.path.exists(output_path):
                print("Error: Output file was not created")
                return

            output_size = os.path.getsize(output_path)
            if output_size == 0:
                print("Error: Output file is empty")
                return

            if output_size > MAX_FILE_SIZE:
                print(f"Error: Output file too large ({output_size} bytes)")
                return

            # Upload the converted file
            dest_bucket = storage_client.bucket(output_bucket_name)
            dest_blob = dest_bucket.blob(output_file_name)
            dest_blob.upload_from_filename(output_path)

            print(
                f"Successfully converted gs://{bucket_name}/{file_name} -> "
                f"gs://{output_bucket_name}/{output_file_name}"
            )

    except subprocess.TimeoutExpired:
        print("Error: ImageMagick conversion timed out")
    except Exception as e:
        # Log error type but not full details to avoid leaking sensitive info
        print(f"Error during image conversion: {type(e).__name__}")
        raise